from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)
SECRET_KEY = 'your-secret-key'  # Replace with your secret key
ALGORITHM = 'RS256'  # Algorithm to be used for signing the JWT
PUBLIC_KEY = 'your-public-key'  # Replace with your public key in PEM format

@app.route('/decode', methods=['POST'])
def decode():
    token = request.json.get('token')
    
    if not token:
        return jsonify({"error": "No token provided"}), 403
  
    try:
        payload = jwt.decode(token, PUBLIC_KEY, algorithms=[ALGORITHM])
        return jsonify(payload), 200
    
    except Exception as e:
        print("Error decoding JWT token: ", str(e))
        return jsonify({"error": "Invalid token or expired token"}), 403

